    [Fact]
    public async Task MultiTrade_DifferentTokenInFails()
    {
        var trade1 = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_2_3], token2, token3), CurrencyAmount<Token>.FromRawAmount(token2, 100), TradeType.EXACT_INPUT);
        var trade2 = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_0_1], token0, token1), CurrencyAmount<Token>.FromRawAmount(token0, 100), TradeType.EXACT_INPUT);
        var trades = new List<Trade<Token, Token>> { trade1, trade2 };
        var ex = Assert.Throws<InvalidOperationException>(() => SwapRouter.SwapCallParameters(trades, new Staker.SwapOptions { SlippageTolerance = slippageTolerance, Recipient = recipient, Deadline = deadline }));
        Assert.Equal("TOKEN_IN_DIFF", ex.Message);
    }

    [Fact]
    public async Task MultiTrade_DifferentTokenOutFails()
