        var trade2 = await Trade<Token, Token>.FromRoute(new Route<Token, Token>([pool_0_1, pool_1_weth], token0, WETH), CurrencyAmount<Token>.FromRawAmount(token0, 100), TradeType.EXACT_INPUT);
